function score(e,t,n){const s=document.querySelector("[name=csrfmiddlewaretoken]").value;$.post({url:"/score",contentType:"application/json",headers:{"X-CSRFToken":s},data:JSON.stringify({answer:t,points:n}),success:t=>{"ok"===t&&($(e).siblings("button.points").removeClass("active"),$(e).addClass("active"))}})}function getRequest(e){$.get({url:e,success:t=>{console.log(`GET ${e}: ${t}`)}})}$(document).ready(function(){$("a.button").click(function(e){if(this.hasAttribute("disabled"))return e.preventDefault(),!1})});